i feel like you're overcomplicating it while delivering little actual results.

when i asked gemini to code the game, it came up with this much simple single-file solution that ran well. i only came here to ask you because i ran out of prompts for the gemini 3 pro tryout and the flash version of gemini was acting pretty stupid, messing everything up. here's the full code for the latest stable version that gemini created:

<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Neon Blade: Melee Arena v9</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #050505; font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; user-select: none; transition: background-color 0.5s; }

        #ui-layer {
            position: absolute; top: 0; left: 0; width: 100%; height: 100%; pointer-events: none;
            display: flex; flex-direction: column; justify-content: space-between;
        }

        #crosshair {
            position: absolute; top: 50%; left: 50%; width: 4px; height: 4px;
            background: white; border-radius: 50%; transform: translate(-50%, -50%);
            box-shadow: 0 0 4px white; opacity: 0.8;
        }
        #hud-top { padding: 20px; display: flex; justify-content: space-between; color: white; font-weight: bold; text-shadow: 0 0 5px #000; }
        #hud-bottom { padding: 20px; display: flex; gap: 20px; align-items: flex-end; }

        .bar-container { width: 250px; height: 12px; background: rgba(0,0,0,0.5); border: 1px solid rgba(255,255,255,0.3); border-radius: 2px; overflow: hidden; position: relative; }
        .bar-fill { height: 100%; width: 100%; transition: width 0.1s linear; }
        #health-fill { background: #ff3333; box-shadow: 0 0 10px #ff3333; }
        #stamina-fill { background: #33ccff; box-shadow: 0 0 10px #33ccff; }

        /* Teleport UI */
        .ability-icon { width: 50px; height: 50px; border: 2px solid #fff; display: flex; align-items: center; justify-content: center; font-weight: bold; color: white; background: rgba(0,0,0,0.5); position: relative; }
        .charges { position: absolute; bottom: -20px; width: 100%; display: flex; justify-content: center; gap: 4px; }
        .charge-pip { width: 10px; height: 10px; background: #555; border-radius: 50%; }
        .charge-active { background: #00ffaa; box-shadow: 0 0 5px #00ffaa; }

        .stat-label { color: white; font-size: 12px; margin-bottom: 4px; display: block; opacity: 0.8; font-weight: bold; letter-spacing: 1px; }

        #start-screen {
            position: absolute; top: 0; left: 0; width: 100%; height: 100%;
            background: rgba(0,0,0,0.85); display: flex; flex-direction: column;
            align-items: center; justify-content: center; color: white; z-index: 10;
            pointer-events: auto; backdrop-filter: blur(5px);
        }
        h1 { font-size: 4rem; margin: 0; color: #33ccff; text-shadow: 0 0 20px #33ccff; letter-spacing: 2px; font-style: italic; }
        p { font-size: 1.2rem; color: #aaa; margin-top: 10px; max-width: 600px; text-align: center; line-height: 1.5; }

        .btn-row { display: flex; gap: 20px; margin-top: 30px; }
        .btn {
            padding: 15px 40px; background: transparent; border: 2px solid #33ccff;
            color: #33ccff; font-size: 1.2rem; cursor: pointer; transition: 0.2s; font-weight: bold;
            text-transform: uppercase;
        }
        .btn:hover { background: #33ccff; color: black; box-shadow: 0 0 20px #33ccff; }
        .btn-secondary { border-color: #fff; color: #fff; }
        .btn-secondary:hover { background: #fff; color: #000; box-shadow: 0 0 20px #fff; }

        #kill-feed { position: absolute; top: 20px; right: 20px; text-align: right; display: flex; flex-direction: column; gap: 5px; }
        .kill-msg { color: white; font-size: 16px; font-weight: bold; text-shadow: 0 0 2px black; animation: fadeOut 3s forwards; border-right: 3px solid #ff3333; padding-right: 10px; }
        @keyframes fadeOut { 0% { opacity: 1; transform: translateX(0); } 80% { opacity: 1; } 100% { opacity: 0; transform: translateX(20px); } }

        #damage-overlay {
            position: absolute; top:0; left:0; width:100%; height:100%;
            background: radial-gradient(circle, transparent 50%, rgba(255,0,0,0.0) 100%);
            pointer-events: none; transition: background 0.1s;
        }

        .light-theme #hud-top, .light-theme .stat-label { color: #333; text-shadow: none; }
        .light-theme #crosshair { background: #333; box-shadow: none; }
        .light-theme .bar-container { background: rgba(0,0,0,0.1); border: 1px solid rgba(0,0,0,0.2); }
    </style>
</head>
<body>

    <div id="damage-overlay"></div>
    <div id="ui-layer">
        <div id="hud-top">
            <div id="score-display">SCORE: 0</div>
            <div id="mode-display">PRESS 'T' TO TOGGLE THEME</div>
        </div>
        <div id="kill-feed"></div>
        <div id="crosshair"></div>
        <div id="hud-bottom">
            <div>
                <span class="stat-label">HEALTH</span>
                <div class="bar-container"><div id="health-fill" class="bar-fill"></div></div>
            </div>
            <div>
                <span class="stat-label">STAMINA</span>
                <div class="bar-container"><div id="stamina-fill" class="bar-fill"></div></div>
            </div>
            <div>
                <div class="ability-icon">Q
                    <div class="charges">
                        <div id="tp-1" class="charge-pip charge-active"></div>
                        <div id="tp-2" class="charge-pip charge-active"></div>
                        <div id="tp-3" class="charge-pip charge-active"></div>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <div id="start-screen">
        <h1>NEON BLADE</h1>
        <p>
            <strong>WASD</strong> Move | <strong>SPACE</strong> Jump / Wall Jump | <strong>SHIFT</strong> Sprint<br>
            <strong>C</strong> Slide/Crouch | <strong>Hold Q + Click</strong> Teleport | <strong>T</strong> Theme
        </p>
        <div class="btn-row">
            <button class="btn" id="start-btn">ENTER ARENA</button>
            <button class="btn btn-secondary" id="theme-btn">TOGGLE THEME</button>
        </div>
    </div>

    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>

    <script>
        // --- CONFIGURATION ---
        const CONFIG = {
            baseSpeed: 14,
            crouchSpeed: 6,
            sprintSpeed: 28,

            jumpForce: 24,
            wallJumpForce: 22,
            wallPushForce: 20,
            gravity: 40,

            frictionGround: 6.0, 
            frictionAir: 1.5,
            frictionSlide: 1.2, 
            slideBoost: 18, 
            bunnyHopBoost: 8,

            staminaMax: 100,
            staminaDrain: 25, 
            staminaRegen: 15,

            attackRange: 8,
            attackCooldown: 250,
            playerDamage: 40, 

            teleportMax: 3,
            teleportCooldown: 5000, // 5s per charge
            teleportRange: 120,

            botHP: 100,
            botDamage: 5,
            botAttackCooldown: 1500,
            botSpeed: 10,
            botSprintSpeed: 18, 
            botRoamSpeed: 6,
            botAggroDuration: 5000, 
            botReactionDelay: 1000,

            regenDelay: 4000,
            regenRate: 25
        };

        // --- AUDIO SYSTEM ---
        const AudioSys = {
            ctx: null,
            init: function() {
                window.AudioContext = window.AudioContext || window.webkitAudioContext;
                this.ctx = new AudioContext();
            },
            playTone: function(freq, type, duration, vol=0.1) {
                if(!this.ctx) return;
                const osc = this.ctx.createOscillator();
                const gain = this.ctx.createGain();
                osc.type = type;
                osc.frequency.setValueAtTime(freq, this.ctx.currentTime);
                gain.gain.setValueAtTime(vol, this.ctx.currentTime);
                gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration);
                osc.connect(gain);
                gain.connect(this.ctx.destination);
                osc.start();
                osc.stop(this.ctx.currentTime + duration);
            },
            playNoise: function(duration, vol=0.1) {
                if(!this.ctx) return;
                const bufferSize = this.ctx.sampleRate * duration;
                const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
                const data = buffer.getChannelData(0);
                for (let i = 0; i < bufferSize; i++) data[i] = Math.random() * 2 - 1;
                const noise = this.ctx.createBufferSource();
                noise.buffer = buffer;
                const gain = this.ctx.createGain();
                gain.gain.setValueAtTime(vol, this.ctx.currentTime);
                gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration);
                const filter = this.ctx.createBiquadFilter();
                filter.type = 'lowpass';
                filter.frequency.value = 1000;
                noise.connect(filter);
                filter.connect(gain);
                gain.connect(this.ctx.destination);
                noise.start();
            },
            playJump: function() { this.playTone(150, 'sine', 0.15, 0.1); },
            playWallJump: function() { this.playTone(300, 'square', 0.1, 0.05); },
            playDash: function() { this.playNoise(0.3, 0.2); },
            playSlash: function() { this.playTone(800, 'sawtooth', 0.2, 0.05); },
            playHit: function() { this.playTone(150, 'square', 0.1, 0.1); },
            playTeleport: function() { this.playTone(1200, 'sine', 0.1, 0.1); }
        };

        // --- GLOBAL STATE ---
        let scene, camera, renderer;
        let isLocked = false;
        let lastTime = performance.now();
        const keys = { w: false, a: false, s: false, d: false, space: false, shift: false, c: false, q: false };

        let isDarkTheme = true;
        const materials = {};

        const player = {
            velocity: new THREE.Vector3(),
            onGround: false,
            jumpsRemaining: 2, 
            isSliding: false,
            isCrouching: false,
            isSprinting: false,
            health: 100,
            stamina: 100,
            score: 0,
            isDead: false,
            cameraHeightOffset: 0,
            lastDamageTime: 0,

            // Teleport
            teleportCharges: 3,
            teleportTimer: 0,
            isAimingTeleport: false,
            teleportTarget: null
        };

        const worldObjects = []; 
        const walls = [];        
        const enemies = [];
        const particles = [];

        let slashMesh, teleportMarker;
        let lastAttackTime = 0;

        // --- SETUP ---
        function init() {
            scene = new THREE.Scene();

            camera = new THREE.PerspectiveCamera(80, window.innerWidth / window.innerHeight, 0.1, 1000);
            camera.position.set(0, 2, 0);

            renderer = new THREE.WebGLRenderer({ antialias: true });
            renderer.setSize(window.innerWidth, window.innerHeight);
            renderer.shadowMap.enabled = true;
            renderer.shadowMap.type = THREE.PCFSoftShadowMap;
            document.body.appendChild(renderer.domElement);

            setupLighting();
            createLevel();
            createSlashEffect();
            createTeleportMarker();

            document.addEventListener('keydown', onKeyDown);
            document.addEventListener('keyup', onKeyUp);
            document.addEventListener('mousemove', onMouseMove);
            document.addEventListener('mousedown', onMouseDown);
            window.addEventListener('resize', onWindowResize);

            document.getElementById('start-btn').addEventListener('click', () => {
                document.body.requestPointerLock();
                AudioSys.init(); 
            });
            document.getElementById('theme-btn').addEventListener('click', toggleTheme);

            document.addEventListener('pointerlockchange', () => {
                isLocked = document.pointerLockElement === document.body;
                const screen = document.getElementById('start-screen');
                if (isLocked) {
                    screen.style.display = 'none';
                    if(player.isDead) resetGame();
                } else {
                    screen.style.display = 'flex';
                }
            });

            applyTheme();
            animate();
        }

        function setupLighting() {
            const ambientLight = new THREE.AmbientLight(0x404040, 1.5);
            scene.add(ambientLight);

            const hemiLight = new THREE.HemisphereLight(0xffffff, 0x444444, 0.6);
            hemiLight.position.set(0, 50, 0);
            scene.add(hemiLight);

            const dirLight = new THREE.DirectionalLight(0xffffff, 0.8);
            dirLight.position.set(50, 100, 50);
            dirLight.castShadow = true;
            dirLight.shadow.camera.left = -200;
            dirLight.shadow.camera.right = 200;
            dirLight.shadow.camera.top = 200;
            dirLight.shadow.camera.bottom = -200;
            dirLight.shadow.mapSize.width = 2048;
            dirLight.shadow.mapSize.height = 2048;
            scene.add(dirLight);
        }

        function toggleTheme() {
            isDarkTheme = !isDarkTheme;
            applyTheme();
        }

        function applyTheme() {
            const body = document.body;
            const ui = document.getElementById('ui-layer');

            if (isDarkTheme) {
                scene.background = new THREE.Color(0x050505);
                scene.fog = new THREE.FogExp2(0x050505, 0.006);
                body.style.backgroundColor = "#050505";
                ui.classList.remove('light-theme');

                if(materials.floor) materials.floor.color.setHex(0x111111);
                if(materials.wall) materials.wall.color.setHex(0x222222);
                if(materials.grid) materials.grid.color.setHex(0x00ffff);
                if(materials.slash) materials.slash.color.setHex(0x00ffff);
                if(materials.marker) materials.marker.color.setHex(0x00ffaa);
            } else {
                scene.background = new THREE.Color(0xddeeff);
                scene.fog = new THREE.FogExp2(0xddeeff, 0.003);
                body.style.backgroundColor = "#ddeeff";
                ui.classList.add('light-theme');

                if(materials.floor) materials.floor.color.setHex(0xffffff);
                if(materials.wall) materials.wall.color.setHex(0xeeeeee);
                if(materials.grid) materials.grid.color.setHex(0x000000);
                if(materials.slash) materials.slash.color.setHex(0x0088ff);
                if(materials.marker) materials.marker.color.setHex(0x0088ff);
            }
        }

        // --- LEVEL GENERATION ---
        function createLevel() {
            materials.floor = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.1 });
            materials.wall = new THREE.MeshStandardMaterial({ color: 0x222222, roughness: 0.2 });
            materials.grid = new THREE.LineBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0.3 });
            materials.slash = new THREE.MeshBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0, side: THREE.DoubleSide, depthTest: false });
            materials.marker = new THREE.MeshBasicMaterial({ color: 0x00ffaa, transparent: true, opacity: 0.5 });

            const gridHelper = new THREE.GridHelper(400, 50, 0x00ffff, 0x222222);
            scene.add(gridHelper);

            // Floor
            createBox(0, -1, 0, 400, 2, 400, materials.floor, true);

            // Bounds
            createBox(0, 50, -200, 400, 100, 2, materials.wall, false, true);
            createBox(0, 50, 200, 400, 100, 2, materials.wall, false, true);
            createBox(-200, 50, 0, 2, 100, 400, materials.wall, false, true);
            createBox(200, 50, 0, 2, 100, 400, materials.wall, false, true);

            // --- VERTICALITY UPGRADE ---

            // Central Spire
            createBox(0, 15, 0, 20, 30, 20, materials.wall);

            // Tall Pillars for Wall Bouncing
            createBox(-50, 25, -50, 10, 50, 10, materials.wall);
            createBox(50, 25, 50, 10, 50, 10, materials.wall);
            createBox(-50, 25, 50, 10, 50, 10, materials.wall);
            createBox(50, 25, -50, 10, 50, 10, materials.wall);

            // Suspended Platforms
            createBox(0, 30, -60, 40, 2, 20, materials.wall, true);
            createBox(0, 45, 60, 40, 2, 20, materials.wall, true);
            createBox(-70, 20, 0, 20, 2, 40, materials.wall, true);

            // Ramps
            createRamp(30, 0, 0, 10, 30, 0.5); // Leads up central
            createRamp(-30, 0, 0, 10, 30, 0.5); 

            // Slide tunnels
            createBox(0, 2.5, 60, 10, 1, 20, materials.wall); 
        }

        function createBox(x, y, z, w, h, d, mat, isFloor=false, isWall=false) {
            const geo = new THREE.BoxGeometry(w, h, d);
            const mesh = new THREE.Mesh(geo, mat);
            mesh.position.set(x, y, z);
            mesh.castShadow = true;
            mesh.receiveShadow = true;
            const edges = new THREE.EdgesGeometry(geo);
            const line = new THREE.LineSegments(edges, materials.grid);
            mesh.add(line);
            scene.add(mesh);
            mesh.geometry.computeBoundingBox();
            if (isFloor || !isWall) worldObjects.push(mesh);
            if (!isFloor) walls.push(mesh);
            return mesh;
        }

        function createRamp(x, yBase, z, width, length, slopeAngle) {
            const height = Math.sin(slopeAngle) * length;
            const geo = new THREE.BoxGeometry(width, 1, length);
            const mesh = new THREE.Mesh(geo, materials.floor);
            mesh.position.set(x, yBase + (height/2), z);
            mesh.rotation.x = -slopeAngle;
            mesh.castShadow = true;
            mesh.receiveShadow = true;
            const edges = new THREE.EdgesGeometry(geo);
            const line = new THREE.LineSegments(edges, materials.grid);
            mesh.add(line);
            scene.add(mesh);
            mesh.updateMatrixWorld();
            worldObjects.push(mesh);
            return mesh;
        }

        // --- VISUALS ---
        function createSlashEffect() {
            const shape = new THREE.Shape();
            shape.absarc(0, 0, 1.2, 0, Math.PI/2, false);
            shape.absarc(0, 0, 1.0, Math.PI/2, 0, true);
            const geo = new THREE.ShapeGeometry(shape);
            geo.center();
            slashMesh = new THREE.Mesh(geo, materials.slash);
            slashMesh.position.set(0, 0, -1.5);
            slashMesh.visible = false;
            camera.add(slashMesh);
            scene.add(camera);
        }

        function createTeleportMarker() {
            const geo = new THREE.CylinderGeometry(0.1, 0.5, 2, 8);
            teleportMarker = new THREE.Mesh(geo, materials.marker);
            teleportMarker.visible = false;
            scene.add(teleportMarker);
        }

        // --- GAME LOGIC ---
        function updatePlayer(dt) {
            if (player.isDead) return;

            camera.position.y -= player.cameraHeightOffset;

            // Teleport Refill
            if (player.teleportCharges < CONFIG.teleportMax) {
                player.teleportTimer += dt * 1000;
                if (player.teleportTimer > CONFIG.teleportCooldown) {
                    player.teleportCharges++;
                    player.teleportTimer = 0;
                    updateTeleportUI();
                }
            }

            // Teleport Aiming
            if (keys.q && player.teleportCharges > 0) {
                player.isAimingTeleport = true;
                const raycaster = new THREE.Raycaster();
                raycaster.setFromCamera(new THREE.Vector2(0, 0), camera);
                raycaster.far = CONFIG.teleportRange;
                const intersects = raycaster.intersectObjects(worldObjects);

                if (intersects.length > 0) {
                    teleportMarker.visible = true;
                    teleportMarker.position.copy(intersects[0].point);
                    teleportMarker.position.y += 1; // Float slightly
                    player.teleportTarget = intersects[0].point;
                } else {
                    teleportMarker.visible = false;
                    player.teleportTarget = null;
                }
            } else {
                player.isAimingTeleport = false;
                teleportMarker.visible = false;
            }

            const now = performance.now();

            if (now - player.lastDamageTime > CONFIG.regenDelay && player.health < 100) {
                player.health += CONFIG.regenRate * dt;
                if (player.health > 100) player.health = 100;
            }

            const isMoving = (keys.w || keys.a || keys.s || keys.d);
            player.isSprinting = keys.shift && player.stamina > 0 && isMoving && !player.isCrouching;

            if (player.isSprinting) {
                player.stamina -= CONFIG.staminaDrain * dt;
                if (player.stamina < 0) player.stamina = 0;
            } else {
                player.stamina += CONFIG.staminaRegen * dt;
                if (player.stamina > 100) player.stamina = 100;
            }

            if (keys.c) {
                if (player.onGround) {
                    const speed = new THREE.Vector2(player.velocity.x, player.velocity.z).length();
                    if ((player.isSprinting || player.isSliding || speed > CONFIG.baseSpeed) && !player.isCrouching) {
                        if (!player.isSliding) {
                            player.isSliding = true;
                            const forward = new THREE.Vector3();
                            camera.getWorldDirection(forward);
                            forward.y = 0; forward.normalize();
                            player.velocity.addScaledVector(forward, CONFIG.slideBoost);
                            AudioSys.playDash();
                        }
                    } else if (!player.isSliding) {
                        player.isCrouching = true;
                    }
                }
            } else {
                player.isSliding = false;
                player.isCrouching = false;
            }

            const targetHeight = (player.isSliding || player.isCrouching) ? -0.8 : 0;
            player.cameraHeightOffset = THREE.MathUtils.lerp(player.cameraHeightOffset, targetHeight, dt * 15);

            const forward = new THREE.Vector3();
            const right = new THREE.Vector3();
            camera.getWorldDirection(forward);
            forward.y = 0; forward.normalize();
            right.crossVectors(forward, new THREE.Vector3(0, 1, 0)).normalize();

            const inputDir = new THREE.Vector3();
            if (keys.w) inputDir.add(forward);
            if (keys.s) inputDir.sub(forward);
            if (keys.a) inputDir.sub(right);
            if (keys.d) inputDir.add(right);
            if (inputDir.length() > 0) inputDir.normalize();

            let targetSpeed = CONFIG.baseSpeed;
            if (player.isCrouching) targetSpeed = CONFIG.crouchSpeed;
            if (player.isSprinting) targetSpeed = CONFIG.sprintSpeed;

            let friction = player.onGround ? CONFIG.frictionGround : CONFIG.frictionAir;
            if (player.isSliding) {
                friction = CONFIG.frictionSlide; 
                targetSpeed = 0; 
            }

            if (inputDir.length() > 0 && !player.isSliding) {
                player.velocity.addScaledVector(inputDir, targetSpeed * friction * dt);
            }

            const damping = Math.exp(-friction * dt);
            player.velocity.x *= damping;
            player.velocity.z *= damping;

            player.velocity.y -= CONFIG.gravity * dt;

            const nextPos = camera.position.clone().addScaledVector(player.velocity, dt);
            const playerBox = new THREE.Box3();
            const radius = 0.4;

            playerBox.min.set(nextPos.x - radius, nextPos.y - 1.5, nextPos.z - radius);
            playerBox.max.set(nextPos.x + radius, nextPos.y + 0.5, nextPos.z + radius);

            for (const wall of walls) {
                const box = wall.geometry.boundingBox.clone();
                box.applyMatrix4(wall.matrixWorld);
                if (playerBox.intersectsBox(box)) {
                    const pX = Math.min(playerBox.max.x - box.min.x, box.max.x - playerBox.min.x);
                    const pZ = Math.min(playerBox.max.z - box.min.z, box.max.z - playerBox.min.z);
                    if (pX < pZ) {
                        player.velocity.x = 0;
                        nextPos.x = (nextPos.x < box.min.x) ? box.min.x - radius - 0.01 : box.max.x + radius + 0.01;
                    } else {
                        player.velocity.z = 0;
                        nextPos.z = (nextPos.z < box.min.z) ? box.min.z - radius - 0.01 : box.max.z + radius + 0.01;
                    }
                }
            }

            const rayOrigin = nextPos.clone();
            const raycaster = new THREE.Raycaster(rayOrigin, new THREE.Vector3(0, -1, 0), 0, 5); 
            const intersects = raycaster.intersectObjects(worldObjects);

            player.onGround = false;

            if (intersects.length > 0) {
                const dist = intersects[0].distance;
                const desiredHeight = 1.6; 

                if (dist < desiredHeight + 0.2 && player.velocity.y <= 0) {
                    nextPos.y = intersects[0].point.y + desiredHeight;
                    player.velocity.y = 0;
                    player.onGround = true;
                    player.jumpsRemaining = 2; 
                }
            }

            camera.position.copy(nextPos);
            camera.position.y += player.cameraHeightOffset;

            if (camera.position.y < -20) {
                damagePlayer(20);
                camera.position.set(0, 10, 0);
                player.velocity.set(0,0,0);
            }
        }

        // --- TELEPORT & UI ---
        function tryTeleport() {
            if (player.teleportCharges > 0 && player.teleportTarget) {
                player.teleportCharges--;
                updateTeleportUI();

                // Execute
                camera.position.set(player.teleportTarget.x, player.teleportTarget.y + 1.6, player.teleportTarget.z);
                // Keep momentum, but reset Y velocity to allow chaining jumps
                player.velocity.y = 2; // Slight hop
                player.jumpsRemaining = 1; // Give 1 jump back if air
                AudioSys.playTeleport();
                spawnParticles(player.teleportTarget, 0x00ffaa, 15);
            }
        }

        function updateTeleportUI() {
            for(let i=1; i<=3; i++) {
                const el = document.getElementById('tp-'+i);
                if (i <= player.teleportCharges) el.classList.add('charge-active');
                else el.classList.remove('charge-active');
            }
        }

        // --- ATTACK ---
        function slash() {
            const now = performance.now();
            if (now - lastAttackTime < CONFIG.attackCooldown) return;
            lastAttackTime = now;

            AudioSys.playSlash();
            playSlashAnim();

            const raycaster = new THREE.Raycaster();
            raycaster.setFromCamera(new THREE.Vector2(0, 0), camera);
            raycaster.far = CONFIG.attackRange;

            const hits = raycaster.intersectObjects(enemies.map(e => e.mesh));
            if (hits.length > 0) {
                const enemy = enemies.find(e => e.mesh === hits[0].object);
                if (enemy) {
                    enemy.takeHit(CONFIG.playerDamage);
                    spawnParticles(hits[0].point, 0x00ffff, 10);
                    AudioSys.playHit();
                }
            }
        }

        function playSlashAnim() {
            slashMesh.visible = true;
            slashMesh.material.opacity = 1;
            const scaleX = Math.random() < 0.5 ? 1 : -1;
            const scaleY = Math.random() < 0.5 ? 1 : -1;
            slashMesh.scale.set(0.5 * scaleX, 0.5 * scaleY, 1);
            slashMesh.rotation.z = Math.random() * 0.5; 

            let progress = 0;
            function animateSlash() {
                progress += 0.2; 
                slashMesh.scale.set( (1 + progress) * scaleX, (1 + progress) * scaleY, 1);
                slashMesh.rotation.z += 0.1;
                slashMesh.material.opacity = 1 - progress;
                if (progress < 1) requestAnimationFrame(animateSlash);
                else slashMesh.visible = false;
            }
            animateSlash();
        }

        // --- ENEMY AI ---
        class Enemy {
            constructor() {
                const geo = new THREE.BoxGeometry(1, 2, 1);
                const mat = new THREE.MeshStandardMaterial({ color: 0x006400 });
                this.mesh = new THREE.Mesh(geo, mat);

                let x, z;
                do {
                    x = (Math.random() - 0.5) * 200;
                    z = (Math.random() - 0.5) * 200;
                } while (Math.abs(x) < 20 && Math.abs(z) < 20);

                this.mesh.position.set(x, 5, z);
                this.health = CONFIG.botHP;
                this.velocity = new THREE.Vector3();
                this.jumps = 0;

                this.state = 'ROAM'; 
                this.reactionTimer = 0;
                this.targetPos = new THREE.Vector3();
                this.pickRoamTarget();
                this.aggroTimer = 0;
                this.lastAttack = 0;
                this.actionTimer = 0; 
                this.isSprinting = false;
                this.isSliding = false;

                scene.add(this.mesh);
                enemies.push(this);
            }

            pickRoamTarget() {
                this.targetPos.set(
                    (Math.random() - 0.5) * 150,
                    this.mesh.position.y,
                    (Math.random() - 0.5) * 150
                );
            }

            update(dt, playerPos) {
                if(this.health <= 0) return;

                this.velocity.y -= CONFIG.gravity * dt;

                if (this.reactionTimer > 0) {
                    this.reactionTimer -= dt * 1000;
                    this.mesh.position.y += this.velocity.y * dt;
                    if(this.mesh.position.y < 1) { this.mesh.position.y = 1; this.velocity.y = 0; }
                    if (this.reactionTimer <= 0) {
                        this.state = 'AGGRO';
                        this.aggroTimer = CONFIG.botAggroDuration;
                        this.mesh.material.color.setHex(0x8b0000); 
                    }
                    return; 
                }

                this.actionTimer -= dt;
                if (this.actionTimer <= 0) {
                    this.actionTimer = 0.5 + Math.random() * 1.5; 
                    this.isSprinting = Math.random() < 0.4;
                    this.isSliding = this.isSprinting && Math.random() < 0.1;
                    if (this.state === 'ROAM' && Math.random() < 0.3) this.pickRoamTarget();

                    if (Math.random() < 0.3) {
                        if (this.mesh.position.y <= 1.2) {
                            this.velocity.y = 18; 
                            this.jumps = 1;
                        } else if (this.jumps < 2 && Math.random() < 0.5) {
                            this.velocity.y = 18; 
                            this.jumps = 2;
                        }
                    }
                }

                let speed = this.isSprinting ? CONFIG.botSprintSpeed : CONFIG.botSpeed;
                if (this.state === 'ROAM') speed = CONFIG.botRoamSpeed;
                if (this.isSliding) speed *= 1.5; 

                let dest = this.targetPos;

                if (this.state === 'AGGRO') {
                    dest = playerPos;
                    this.aggroTimer -= dt * 1000;
                    if (this.aggroTimer <= 0) {
                        this.state = 'ROAM';
                        this.mesh.material.color.setHex(0x006400); 
                    }
                } else {
                     if (new THREE.Vector2(this.mesh.position.x - dest.x, this.mesh.position.z - dest.z).length() < 3) {
                        this.pickRoamTarget();
                    }
                }

                const dir = new THREE.Vector3().subVectors(dest, this.mesh.position);
                dir.y = 0; dir.normalize();

                this.mesh.position.addScaledVector(dir, speed * dt);
                this.mesh.position.y += this.velocity.y * dt;

                if(this.mesh.position.y < 1) { 
                    this.mesh.position.y = 1; 
                    this.velocity.y = 0; 
                    this.jumps = 0; 
                }

                this.mesh.lookAt(dest.x, this.mesh.position.y, dest.z);

                if (this.isSliding) {
                    this.mesh.scale.set(1, 0.5, 1);
                    this.mesh.position.y -= 0.5; 
                } else {
                    this.mesh.scale.set(1, 1, 1);
                }

                if (this.state === 'AGGRO') {
                    const dist = this.mesh.position.distanceTo(playerPos);
                    const now = performance.now();
                    if (dist < 2.5 && (now - this.lastAttack > CONFIG.botAttackCooldown)) {
                        this.lastAttack = now;
                        damagePlayer(CONFIG.botDamage);
                        const push = dir.negate().multiplyScalar(2);
                        this.mesh.position.addScaledVector(push, dt);
                    }
                }
            }

            takeHit(amt) {
                this.health -= amt;
                this.mesh.material.color.setHex(0xffffff); 
                setTimeout(() => { 
                    if(this.health > 0) {
                        if(this.state === 'AGGRO') this.mesh.material.color.setHex(0x8b0000);
                        else this.mesh.material.color.setHex(0x006400);
                    }
                }, 100);

                if (this.state !== 'AGGRO' && this.reactionTimer <= 0) {
                    this.reactionTimer = CONFIG.botReactionDelay;
                }

                if (this.health <= 0) {
                    scene.remove(this.mesh);
                    enemies.splice(enemies.indexOf(this), 1);
                    addScore(100);
                    showKillMessage("BOT DESTROYED");
                    spawnParticles(this.mesh.position, 0x8b0000, 20);
                    AudioSys.playHit();
                }
            }
        }

        function spawnParticles(pos, col, count) {
            for(let i=0; i<count; i++) {
                const m = new THREE.Mesh(new THREE.BoxGeometry(0.2,0.2,0.2), new THREE.MeshBasicMaterial({color: col}));
                m.position.copy(pos);
                scene.add(m);
                particles.push({
                    mesh: m, 
                    vel: new THREE.Vector3((Math.random()-0.5)*10, (Math.random()-0.5)*10, (Math.random()-0.5)*10),
                    life: 0.5
                });
            }
        }

        function updateParticles(dt) {
            for(let i=particles.length-1; i>=0; i--) {
                const p = particles[i];
                p.life -= dt * 2;
                p.mesh.position.addScaledVector(p.vel, dt);
                p.mesh.scale.setScalar(p.life);
                if(p.life <= 0) { scene.remove(p.mesh); particles.splice(i, 1); }
            }
        }

        function onKeyDown(e) {
            if(e.code === 'KeyT') toggleTheme();
            switch(e.code) {
                case 'KeyW': keys.w = true; break;
                case 'KeyA': keys.a = true; break;
                case 'KeyS': keys.s = true; break;
                case 'KeyD': keys.d = true; break;
                case 'KeyC': keys.c = true; break;
                case 'KeyQ': keys.q = true; break;
                case 'ShiftLeft': keys.shift = true; break;
                case 'Space': 
                    if(player.onGround) { 
                        if (player.isSliding) {
                            const forward = new THREE.Vector3();
                            camera.getWorldDirection(forward);
                            forward.y = 0; forward.normalize();
                            player.velocity.addScaledVector(forward, CONFIG.bunnyHopBoost);
                        }
                        player.velocity.y = CONFIG.jumpForce; 
                        player.onGround = false; 
                        player.jumpsRemaining--;
                        AudioSys.playJump();
                    } else {
                        if(checkWallJump()) return; 
                        if (player.jumpsRemaining > 0) {
                            player.velocity.y = CONFIG.jumpForce;
                            player.jumpsRemaining--;
                            AudioSys.playJump();
                        }
                    }
                    break;
            }
        }

        function checkWallJump() {
            const directions = [
                new THREE.Vector3(1,0,0), new THREE.Vector3(-1,0,0),
                new THREE.Vector3(0,0,1), new THREE.Vector3(0,0,-1)
            ];
            const raycaster = new THREE.Raycaster();
            const pos = camera.position.clone();
            pos.y -= 1.0; 

            for(let dir of directions) {
                raycaster.set(pos, dir);
                const intersects = raycaster.intersectObjects(walls);
                if(intersects.length > 0 && intersects[0].distance < 1.5) {
                    const pushDir = dir.negate().normalize();
                    player.velocity.set(0,0,0); 
                    player.velocity.addScaledVector(pushDir, CONFIG.wallPushForce);
                    player.velocity.y = CONFIG.wallJumpForce;
                    AudioSys.playWallJump();
                    return true;
                }
            }
            return false;
        }

        function onKeyUp(e) {
            switch(e.code) {
                case 'KeyW': keys.w = false; break;
                case 'KeyA': keys.a = false; break;
                case 'KeyS': keys.s = false; break;
                case 'KeyD': keys.d = false; break;
                case 'KeyC': keys.c = false; break;
                case 'KeyQ': keys.q = false; break;
                case 'ShiftLeft': keys.shift = false; break;
            }
        }
        function onMouseMove(e) {
            if(!isLocked) return;
            camera.rotation.y -= e.movementX * 0.002;
            camera.rotation.x -= e.movementY * 0.002;
            camera.rotation.x = Math.max(-1.5, Math.min(1.5, camera.rotation.x));
            camera.rotation.order = "YXZ";
        }
        function onMouseDown(e) {
            if(isLocked && e.button === 0) {
                if (player.isAimingTeleport && player.teleportCharges > 0) {
                    tryTeleport();
                } else {
                    slash();
                }
            }
        }

        function damagePlayer(n) {
            if(player.isDead) return;
            player.health -= n;
            player.lastDamageTime = performance.now();
            document.getElementById('damage-overlay').style.background = `radial-gradient(circle, transparent 50%, rgba(255,0,0,0.5) 100%)`;
            setTimeout(()=>document.getElementById('damage-overlay').style.background = `radial-gradient(circle, transparent 50%, rgba(255,0,0,0.0) 100%)`, 200);
            if(player.health <= 0) {
                player.isDead = true;
                document.exitPointerLock();
                document.getElementById('start-screen').style.display = 'flex';
                document.querySelector('#start-screen h1').innerText = "GAME OVER";
                document.querySelector('#start-screen p').innerHTML = `Score: ${player.score}<br>Click to Restart`;
            }
        }

        function showKillMessage(msg) {
            const feed = document.getElementById('kill-feed');
            const el = document.createElement('div');
            el.className = 'kill-msg';
            el.innerText = msg;
            feed.appendChild(el);
            setTimeout(() => { el.style.opacity = 0; setTimeout(() => el.remove(), 1000); }, 2000);
        }

        function addScore(n) { player.score += n; document.getElementById('score-display').innerText = "SCORE: "+player.score; }

        function resetGame() {
            player.health = 100; player.stamina = 100; player.score = 0; player.isDead = false;
            player.teleportCharges = 3;
            updateTeleportUI();
            player.velocity.set(0,0,0); camera.position.set(0,2,0);
            enemies.forEach(e=>scene.remove(e.mesh)); enemies.length = 0;
            addScore(0);
            document.querySelector('#start-screen h1').innerText = "NEON BLADE";
            document.getElementById('kill-feed').innerHTML = '';
        }

        function onWindowResize() {
            camera.aspect = window.innerWidth/window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        function animate() {
            requestAnimationFrame(animate);
            const t = performance.now();
            const dt = Math.min((t - lastTime)/1000, 0.1);
            lastTime = t;

            if(isLocked) {
                if(Math.random() < 0.01 && enemies.length < 12) new Enemy();
                updatePlayer(dt);
                enemies.forEach(e => e.update(dt, camera.position));
                updateParticles(dt);

                document.getElementById('health-fill').style.width = player.health + '%';
                document.getElementById('stamina-fill').style.width = player.stamina + '%';
                document.getElementById('stamina-fill').style.backgroundColor = player.isSprinting ? '#ffffff' : '#33ccff';
            }
            renderer.render(scene, camera);
        }

        init();
    </script>
</body>
